/**
 * Component Bundle Exporter
 * Multi-component ZIP bundle generator with deduplicated CSS, merged HTML,
 * auto-generated README, and named export history.
 *
 * Builds on top of Download.js extraction infrastructure.
 * JSZip loaded on-demand from CDN (same pattern as Download).
 */

const BundleExporter = (function () {
  const STORAGE_KEY = 'uiverse_bundle_export_history';
  const MAX_HISTORY = 20;

  function safeStorage() {
    try { return window.localStorage; } catch (_) { return null; }
  }

  function readJson(text, fallback) {
    try { return JSON.parse(text); } catch (_) { return fallback; }
  }

  function getHistory() {
    const storage = safeStorage();
    if (!storage) return [];
    try {
      const raw = storage.getItem(STORAGE_KEY);
      return raw ? readJson(raw, []) : [];
    } catch (_) { return []; }
  }

  function saveHistory(history) {
    const storage = safeStorage();
    if (!storage) return;
    try {
      storage.setItem(STORAGE_KEY, JSON.stringify(history.slice(-MAX_HISTORY)));
    } catch (_) { /* ignore */ }
  }

  function recordExport(name, items) {
    const history = getHistory();
    history.push({
      name,
      items: items.map((i) => ({ label: i.label, html: i.html?.substring(0, 200) || '' })),
      count: items.length,
      at: new Date().toISOString()
    });
    saveHistory(history);
  }

  function loadJSZip() {
    if (window.JSZip) return Promise.resolve(window.JSZip);
    return new Promise((resolve, reject) => {
      const script = document.createElement('script');
      script.src = 'https://cdn.jsdelivr.net/npm/jszip@3.10.1/dist/jszip.min.js';
      script.async = true;
      script.onload = () => resolve(window.JSZip);
      script.onerror = () => reject(new Error('Failed to load JSZip'));
      document.head.appendChild(script);
    });
  }

  function downloadBlob(blob, filename) {
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = filename;
    link.rel = 'noopener';
    document.body.appendChild(link);
    link.click();
    link.remove();
    setTimeout(() => URL.revokeObjectURL(url), 1200);
  }

  function deduplicateCss(cssChunks) {
    // Simple deduplication: split by rule blocks, track unique selectors
    const seen = new Set();
    const deduped = [];

    cssChunks.forEach((chunk) => {
      const rules = String(chunk || '').split(/(?=\}[ \t]*\n*[a-zA-Z.#\[\*:])|(?=\}[ \t]*\n*$)/);
      rules.forEach((rule) => {
        const trimmed = rule.trim();
        if (!trimmed) return;
        // Extract selector (everything before first {)
        const selectorMatch = trimmed.match(/^([^{]+)\{/);
        const selector = selectorMatch ? selectorMatch[1].trim() : trimmed;
        const key = selector.replace(/\s+/g, ' ');
        if (seen.has(key)) return;
        seen.add(key);
        deduped.push(trimmed);
      });
    });

    return deduped.join('\n\n');
  }

  function buildBundleHtml(items) {
    const sections = items.map((item, idx) => `
<!-- ===== ${item.label || 'Component ' + (idx + 1)} ===== -->
<section class="bundle-component" id="component-${idx}">
  <h2 class="bundle-component-title">${item.label || 'Component ' + (idx + 1)}</h2>
  ${item.html || '<!-- No HTML -->'}
</section>
`).join('\n\n');

    return `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>UIverse Component Bundle</title>
  <link rel="stylesheet" href="components.css">
</head>
<body>
  <header class="bundle-header">
    <h1>UIverse Component Bundle</h1>
    <p>${items.length} component${items.length !== 1 ? 's' : ''} included</p>
  </header>
  <main class="bundle-main">
${sections}
  </main>
  <script src="components.js"></script>
</body>
</html>`;
  }

  function buildReadme(items, bundleName) {
    const componentsList = items.map((item, idx) => `
### ${idx + 1}. ${item.label || 'Untitled'}

${item.description || 'No description available.'}

**HTML Usage:**
\`\`\`html
${item.html || '<!-- No HTML -->'}
\`\`\`

**CSS:**
\`\`\`css
${item.css || '/* No CSS */'}
\`\`\`
`).join('\n');

    return `# ${bundleName}

Generated by UIverse Component Bundle Exporter.

## Contents

| # | Component | Description |
|---|-----------|-------------|
${items.map((item, idx) => `| ${idx + 1} | ${item.label || 'Untitled'} | ${item.description?.substring(0, 60) || '—'} |`).join('\n')}

## Files

- \`index.html\` — All components rendered in a single page
- \`components.css\` — Combined and deduplicated styles
- \`components.js\` — Combined JavaScript
- \`README.md\` — This file

## Usage

1. Extract the ZIP
2. Open \`index.html\` in your browser to preview
3. Copy individual component HTML/CSS from this README or from \`index.html\`

---

${componentsList}

---

*Generated by UIverse — https://uiverse.io*
`;
  }

  async function generateBundle(items, options = {}) {
    const name = options.name || 'uiverse-bundle';
    const filename = name.replace(/[^a-z0-9_-]/gi, '-').toLowerCase() + '.zip';

    const JSZip = await loadJSZip();
    const zip = new JSZip();

    const html = buildBundleHtml(items);
    const css = deduplicateCss(items.map((i) => i.css).filter(Boolean));
    const js = items.map((i) => i.js).filter(Boolean).join('\n\n// ----------------------------------------\n\n');

    zip.file('index.html', html);
    zip.file('components.css', css || '/* No component styles */');
    zip.file('components.js', js || '// No component scripts');
    zip.file('README.md', buildReadme(items, name));

    const blob = await zip.generateAsync({ type: 'blob' });
    downloadBlob(blob, filename);
    recordExport(name, items);

    return { name, filename, count: items.length };
  }

  function getHistoryList() {
    return getHistory();
  }

  function clearHistory() {
    const storage = safeStorage();
    if (storage) {
      try { storage.removeItem(STORAGE_KEY); } catch (_) { /* ignore */ }
    }
  }

  return {
    generateBundle,
    getHistoryList,
    clearHistory,
    deduplicateCss,
    buildReadme
  };
})();

if (typeof module !== 'undefined' && module.exports) {
  module.exports = BundleExporter;
}

window.BundleExporter = BundleExporter;